import { InView } from 'react-intersection-observer';
import styled from "styled-components"
import SectionHeader from './SectionHeader'

const Projects = ({ id }) => {
  return (
    <ProjectsContainer id={id}>
      <InView triggerOnce>
        {({ inView, ref, entry }) => (
          <SectionHeader inView={inView} ref={ref} />
        )}
      </InView>

      <ProjectsList>
        <Project>
          <h4> Vans Scrapper Website </h4>
          <ul>
            <li> React </li>
            <li> React Redux </li>
            <li> Express </li>
            <li> Mongoose </li>
            <li> Puppeteer </li>
            <li> Styled Components </li>
          </ul>
          <span> app that takes data from Vans page every 24 hours using scrapping
            so they can be displayed with filtering and favourites afterwards, 
            which is not possible on the official page. Purpose of creating such project
            was to create a page that will be more enjoyable to use than the predecessor.
          </span>
        </Project>
        <Project>
          <h4> Nekiro.dev </h4>
          <ul>
            <li> PHP Laravel </li>
          </ul>
          <span> desc </span>
        </Project>
      </ProjectsList>
    </ProjectsContainer>
  )
}

const ProjectsContainer = styled.section`
  width: 100%;
  /* height: 100vh; */
  padding: 3em 0 5em 0;
  color: white;
  /* font-size: 3em; */
`

const ProjectsList = styled.ul`
  margin-top: 5em;
  padding-left: 5em;
  display: grid;
  grid-template-columns: auto;
  width: 100%;
  padding-left: 15em;
  /* row-gap: 5em; */
  width: fit-content;
`

const Project = styled.li`
  display: flex;
  flex-direction: column;
  row-gap: 1em;
  cursor: pointer;
  padding: 1em;
  transition: 0.5s;

  &:hover {
    background: #242424;
  }

  & h4 {
    margin: 0;
    font-size: 3em;
  }
  
  & ul {
    padding: 0;
    display: flex;
    column-gap: 2em;
    letter-spacing: 1px;
    margin-bottom: 1em;
    text-transform: uppercase;
    font-size: 0.8em;
  }

  & span {
    max-width: 65ch;
    line-height: 2em;
    font-weight: 100;
  }
`

export default Projects
